// Follow-up to assign-certificates.js: every course with an external certification
// body now gets a sample certificate image. Representative SVGs (exact certification
// name per course, body design language) are generated by generate-certificates.mjs
// into public/certificates/gen/. This script points pageSections.certificate.image
// at them. Also flips the mislabeled "SimpliLEAD" course to self-issued and replaces
// the two blank IIBA webp images (cbap, ecba).
// Run: node scripts/assign-certificates-v2.js
const { PrismaClient } = require("@prisma/client");
const fs = require("fs");
const p = new PrismaClient();

(async () => {
  const gen = new Set(fs.readdirSync("public/certificates/gen").filter((f) => f.endsWith(".svg")).map((f) => f.replace(".svg", "")));
  const courses = await p.course.findMany({ select: { id: true, slug: true, accreditedBy: true, pageSections: true } });
  let set = 0, selfed = 0;
  for (const c of courses) {
    const ps = c.pageSections && typeof c.pageSections === "object" ? c.pageSections : {};
    const cert = ps.certificate && typeof ps.certificate === "object" ? ps.certificate : {};
    // Mislabeled self-delivered course: use the Simplilead self-issued design.
    if (c.accreditedBy === "SimpliLEAD") {
      delete cert.image;
      await p.course.update({ where: { id: c.id }, data: { accreditedBy: "Simplilead", pageSections: { ...ps, certificate: cert } } });
      selfed++; console.log("SELF", c.slug);
      continue;
    }
    if (!gen.has(c.slug)) continue;
    const file = `/certificates/gen/${c.slug}.svg`;
    // Overwrite blanks/absent; never downgrade a real non-generated image except the two known-blank IIBA files.
    const blank = cert.image === "/certificates/cbap.webp" || cert.image === "/certificates/ecba.webp";
    if (cert.image && !blank) { console.log("KEEP", c.slug, cert.image); continue; }
    await p.course.update({ where: { id: c.id }, data: { pageSections: { ...ps, certificate: { ...cert, image: file } } } });
    set++; console.log("IMG", c.slug, "->", file);
  }
  console.log(`done: ${set} images assigned, ${selfed} flipped to self-issued`);
  await p.$disconnect();
})();
